-- ============================================================
-- 8. VIEW view_property_clean
-- ============================================================
-- View là bảng ảo, không lưu dữ liệu mới.
-- View này join các bảng đã chuẩn hóa lại với nhau để phân tích dễ hơn.
-- Nhờ có view, khi phân tích chỉ cần SELECT từ view_property_clean thay vì viết JOIN nhiều lần.

CREATE VIEW dbo.view_property_clean AS
SELECT
    p.property_id,
    h.home_type_name,
    p.price_usd,

    CASE
        WHEN p.price_usd < 500000 THEN N'Low price'
        WHEN p.price_usd < 1000000 THEN N'Medium price'
        WHEN p.price_usd < 2000000 THEN N'High price'
        ELSE N'Luxury price'
    END AS price_segment,

    p.bedrooms,
    p.bathrooms,
    p.living_area_sqft,
    p.lot_area_sqft,
    p.lot_to_living_ratio,
    p.bed_bath_ratio,

    l.latitude,
    l.longitude,
    l.distance_to_city,
    l.distance_to_airport,
    l.distance_to_coast,

    s.median_income_usd,
    s.poverty_rate,
    s.unemployment_rate,
    s.population,
    s.bachelor_rate,
    s.median_rent_usd,
    s.area_home_value,
    s.owner_occupied_rate,
    s.population_density,

    r.overall_risk_score,
    r.loss_risk_score,
    r.social_vulnerability_score,
    r.resilience_score,
    r.fire_risk_score,
    r.earthquake_risk_score,
    r.heat_risk_score

FROM dbo.properties p
JOIN dbo.home_types h
    ON p.home_type_id = h.home_type_id
JOIN dbo.property_locations l
    ON p.property_id = l.property_id
JOIN dbo.socioeconomic_profiles s
    ON p.socioeconomic_id = s.socioeconomic_id
JOIN dbo.risk_profiles r
    ON p.risk_profile_id = r.risk_profile_id;
GO

-- ============================================================
-- 9. Query kiểm tra sau khi chạy script
-- ============================================================

SELECT 'raw_zillow_listings' AS table_name, COUNT(*) AS total_rows FROM dbo.raw_zillow_listings
UNION ALL
SELECT 'home_types', COUNT(*) FROM dbo.home_types
UNION ALL
SELECT 'socioeconomic_profiles', COUNT(*) FROM dbo.socioeconomic_profiles
UNION ALL
SELECT 'risk_profiles', COUNT(*) FROM dbo.risk_profiles
UNION ALL
SELECT 'properties', COUNT(*) FROM dbo.properties
UNION ALL
SELECT 'property_locations', COUNT(*) FROM dbo.property_locations;
GO

SELECT TOP 10 *
FROM dbo.view_property_clean;
GO

SELECT
    home_type_name,
    COUNT(*) AS total_properties,
    ROUND(AVG(price_usd), 2) AS avg_price,
    ROUND(MIN(price_usd), 2) AS min_price,
    ROUND(MAX(price_usd), 2) AS max_price
FROM dbo.view_property_clean
GROUP BY home_type_name
ORDER BY avg_price DESC;
GO